import sys

def main():
    M = int(sys.stdin.readline())
    S1 = sys.stdin.readline().strip()
    S2 = sys.stdin.readline().strip()
    S3 = sys.stdin.readline().strip()

    min_time = float('inf')

    # Try each possible digit (0-9)
    for digit in map(str, range(10)):
        # Find all positions where digit appears in each reel
        pos1 = [i for i, ch in enumerate(S1) if ch == digit]
        pos2 = [i for i, ch in enumerate(S2) if ch == digit]
        pos3 = [i for i, ch in enumerate(S3) if ch == digit]

        if not pos1 or not pos2 or not pos3:
            continue  # Not possible to get this digit on all reels

        # Try all combinations of positions
        for t1 in pos1:
            for t2 in pos2:
                for t3 in pos3:
                    # Time to press each button
                    # We can press buttons at different times, but we need to find the max time
                    # because all reels must be stopped by that time
                    time = max(t1, t2, t3)
                    if time < min_time:
                        min_time = time

    if min_time == float('inf'):
        print(-1)
    else:
        print(min_time)

if __name__ == "__main__":
    main()
